$LP="$env:TEMP\driver-install-$(Get-Date -Format 'yyyyMMdd-HHmmss').log";$DP="$env:TEMP\driver-downloads";Write-Host "========================================" -ForegroundColor Cyan;Write-Host "  Universal Driver Installer Script" -ForegroundColor Cyan;Write-Host "========================================" -ForegroundColor Cyan;Write-Host "";Write-Host "Checking administrator privileges..." -ForegroundColor Yellow;if(-not([Security.Principal.WindowsPrincipal][Security.Principal.WindowsIdentity]::GetCurrent()).IsInRole([Security.Principal.WindowsBuiltInRole]"Administrator")){Write-Host "ERROR: This script requires Administrator privileges!" -ForegroundColor Red;Write-Host "Please right-click PowerShell and select 'Run as Administrator'" -ForegroundColor Red;Write-Host "";Read-Host "Press Enter to exit";exit 1};Write-Host "Admin check: OK" -ForegroundColor Green;Write-Host "";function WL{param([string]$M,[string]$L="INFO");$ts=Get-Date -Format "yyyy-MM-dd HH:mm:ss";Write-Host "[$ts] [$L] $M";Add-Content -Path $LP -Value "[$ts] [$L] $M" -EA SilentlyContinue};if(-not(Test-Path $DP)){New-Item -ItemType Directory -Path $DP -Force|Out-Null};WL "Script started";WL "Log file: $LP";$gpu=@();Write-Host "Detecting GPUs..." -ForegroundColor Yellow;Get-WmiObject Win32_VideoController -EA 0|Where-Object{$_.Name}|ForEach-Object{if($_.Name -like "*NVIDIA*"){$gpu+=@{Type="NVIDIA";Name=$_.Name};WL "Found NVIDIA: $($_.Name)"}if($_.Name -like "*AMD*" -or $_.Name -like "*Radeon*"){$gpu+=@{Type="AMD";Name=$_.Name};WL "Found AMD: $($_.Name)"}if($_.Name -like "*Intel*"){$gpu+=@{Type="Intel";Name=$_.Name};WL "Found Intel: $($_.Name)"}};$dev=@();Write-Host "Detecting motherboard devices..." -ForegroundColor Yellow;Get-WmiObject Win32_NetworkAdapterConfiguration -EA 0|Where-Object{$_.Description}|ForEach-Object{$dev+=@{Type="Network";Name=$_.Description};WL "Found Network: $($_.Description)"};Get-WmiObject Win32_SoundDevice -EA 0|Where-Object{$_.Name}|ForEach-Object{$dev+=@{Type="Audio";Name=$_.Name};WL "Found Audio: $($_.Name)"};Get-WmiObject Win32_IDEController -EA 0|Where-Object{$_.Name}|ForEach-Object{$dev+=@{Type="Storage";Name=$_.Name};WL "Found Storage: $($_.Name)"};Get-WmiObject Win32_USBController -EA 0|Where-Object{$_.Name}|ForEach-Object{$dev+=@{Type="USB";Name=$_.Name};WL "Found USB: $($_.Name)"};Get-WmiObject Win32_BaseBoard -EA 0|ForEach-Object{$dev+=@{Type="Motherboard";Name="$($_.Manufacturer) $($_.Product)"};WL "Found Motherboard: $($_.Manufacturer) $($_.Product)"};Write-Host "";Write-Host "========== DETECTED HARDWARE ==========" -ForegroundColor Green;Write-Host "GPUs found: $($gpu.Count)" -ForegroundColor Green;$gpu|ForEach-Object{Write-Host "  - $($_.Type): $($_.Name)" -ForegroundColor Green};Write-Host "";Write-Host "Devices found: $($dev.Count)" -ForegroundColor Green;$dev|Select-Object -First 5|ForEach-Object{Write-Host "  - $($_.Type): $($_.Name)" -ForegroundColor Green};if($dev.Count -gt 5){Write-Host "  ... and $($dev.Count-5) more devices" -ForegroundColor Green};Write-Host "";Write-Host "========== DRIVER DOWNLOAD LINKS ==========" -ForegroundColor Green;if($gpu|Where-Object{$_.Type -eq "NVIDIA"}){Write-Host "";Write-Host "NVIDIA Drivers:" -ForegroundColor Cyan;Write-Host "  https://www.nvidia.com/Download/index.aspx" -ForegroundColor White;WL "NVIDIA driver link provided"};if($gpu|Where-Object{$_.Type -eq "AMD"}){Write-Host "";Write-Host "AMD Drivers:" -ForegroundColor Cyan;Write-Host "  https://www.amd.com/en/technologies/radeon-software" -ForegroundColor White;WL "AMD driver link provided"};if($gpu|Where-Object{$_.Type -eq "Intel"}){Write-Host "";Write-Host "Intel Arc Drivers:" -ForegroundColor Cyan;Write-Host "  https://www.intel.com/content/www/us/en/download/785597/intel-arc-graphics-driver.html" -ForegroundColor White;WL "Intel driver link provided"};$mb=Get-WmiObject Win32_BaseBoard -EA 0;if($mb){$mfg=$mb.Manufacturer.ToLower();Write-Host "";Write-Host "Chipset Drivers:" -ForegroundColor Cyan;if($mfg -like "*intel*"){Write-Host "  https://www.intel.com/content/www/us/en/download/17596/intel-chipset-device-software.html" -ForegroundColor White;WL "Intel Chipset link provided"};if($mfg -like "*amd*"){Write-Host "  https://www.amd.com/en/support" -ForegroundColor White;WL "AMD Chipset link provided"}};Write-Host "";Write-Host "========== NEXT STEPS ==========" -ForegroundColor Cyan;Write-Host "1. Download drivers from the links above" -ForegroundColor Cyan;Write-Host "2. Run the installer executables" -ForegroundColor Cyan;Write-Host "3. Restart your computer" -ForegroundColor Cyan;Write-Host "";Write-Host "Log file: $LP" -ForegroundColor Cyan;WL "Script completed";Write-Host "";Read-Host "Press Enter to exit"
